public:
    string crackSafe(int n, int k) {
        if (n == 1) {
            string res;
            for (int i = 0; i < k; ++i) res += to_string(i);
            return res;
        }
        int total = 1;
        for (int i = 0; i < n; ++i) total *= k;
        string start(n - 1, '0');
        unordered_set<string> seen;
        string res;
        dfs(start, k, seen, res, n);
        res += start;
        return res;
    }
private:
    void dfs(string node, int k, unordered_set<string>& seen, string& res, int n) {
        for (int i = 0; i < k; ++i) {
            string nei = node + to_string(i);
            if (!seen.count(nei)) {
                seen.insert(nei);
                string nextNode = nei.substr(1);
                dfs(nextNode, k, seen, res, n);
                res += to_string(i);
            }
        }
    }
};
